let rawText = $json.output;

try {
  if (!rawText) throw new Error("El campo 'output' no existe");

  // Limpiamos y convertimos a JSON
  const cleanText = rawText.replace(/```json|```/g, "").trim();
  const parsedData = JSON.parse(cleanText);

  // Devolvemos un solo objeto, empacando los correos en la propiedad "correos"
  return {
    json: {
      correos: Array.isArray(parsedData) ? parsedData : [parsedData]
    }
  };

} catch (error) {
  return {
    json: {
      error: "No se pudo extraer un JSON válido",
      mensaje_error: error.message
    }
  };
}

let result = [];

for (const item of $input.all()) {
    const input = item.json;
    let csvContent = "";

    // 1. Extraer el texto del archivo binario
    const binaryKey = item.binary ? Object.keys(item.binary)[0] : null;
    if (binaryKey) {
        const base64Data = item.binary[binaryKey].data;
        csvContent = Buffer.from(base64Data, 'base64').toString('utf8');
    }

    const mensaje = (input.mensaje ?? input.texto ?? csvContent ?? '').toString().trim();

    if (!mensaje) {
        result.push({ json: { __route: 'error', ok: false, errorMessage: 'Archivo vacío o sin mensaje', executionId: $execution.id } });
        continue;
    }

    // 2. Si hay CSV, lo dividimos por filas
    if (csvContent) {
        // Separamos por saltos de línea y filtramos líneas en blanco
        const lines = csvContent.split(/\r?\n/).filter(line => line.trim() !== '');

        // Verificamos que tenga al menos cabecera y 1 fila de datos
        if (lines.length > 1) {
            const headers = lines[0]; // Guardamos la primera línea como cabecera

            // Iteramos desde la línea 1 (omitiendo la cabecera)
            for (let i = 1; i < lines.length; i++) {
                const fila = lines[i];

                // Creamos un nuevo elemento (item) para n8n por cada fila
                result.push({
                    json: {
                        ...input,
                        // Aquí creamos el mini-CSV perfecto para tu Agente IA
                        csv_crudo: headers + "\n" + fila, 
                        numero_fila: i, // Útil para trazabilidad
                        ok: true,
                        __route: 'ok',
                        executionId: $execution.id
                    }
                });
            }
            continue; // Pasamos al siguiente item de entrada
        }
    }

    // 3. Fallback si es solo texto normal o un CSV de una sola línea
    result.push({ 
        json: { 
            ...input, 
            csv_crudo: csvContent, 
            ok: true, 
            __route: 'ok',
            executionId: $execution.id 
        } 
    });
}

return result;
